  /**
   * Creates multiple disbursements in a single batch operation.
   * @param {Object} bulkData - Bulk disbursement data containing an array of disbursement records
   * @returns {Promise<Object>} API response containing batch processing results
   */
  async createBulkDisbursement(bulkData, serviceId = null) {
    logger.debug('Creating bulk disbursement');

    const headers = {};
    const userId = getStoredUserId();

    if (userId) {
      // Ensure userId is a string (UUID from login response: data.user.id)
      headers['x-user-id'] = String(userId);
    } else {
      throw new Error('User ID not found. Please log in again.');
    }

    if (serviceId) {
      headers['service-id'] = String(serviceId);
    }

    // Ensure source field is added to all bulk disbursement records
    const enhancedBulkData = {
      ...bulkData,
      // If bulkData has records array, add source to each record
      records: bulkData.records?.map(record => ({
        ...record,
        source: 'dashboard'
      })),
      // If bulkData has disbursements array, add source to each record
      disbursements: bulkData.disbursements?.map(record => ({
        ...record,
        source: 'dashboard'
      }))
    };

    // Clean up undefined arrays
    if (!enhancedBulkData.records) { delete enhancedBulkData.records; }
    if (!enhancedBulkData.disbursements) { delete enhancedBulkData.disbursements; }

    const data = await apiRequest('/v1/disbursements/bulk-v1', {
      method: 'POST',
      body: JSON.stringify(enhancedBulkData),
      headers,
    });

    logger.debug('Bulk disbursement created');
    return data;
  },

