  /**
   * Creates a Bank B2C (Business-to-Consumer) disbursement transaction.
   * @param {Object} disbursementData - Disbursement payload structure
   * @param {string} disbursementData.reference - Transaction reference
   * @param {Object} disbursementData.customer - Customer/recipient details
   * @param {string} disbursementData.narration - Transaction narration
   * @param {number|string} disbursementData.amount - Disbursement amount
   * @param {string} [disbursementData.currency='GHS'] - Currency code
   * @param {Object} disbursementData.paymentDetails - Payment details including bank account info
   * @param {string} disbursementData.paymentDetails.accountNumber - Bank account number
   * @param {string} disbursementData.paymentDetails.accountName - Account holder name
   * @param {string} disbursementData.paymentDetails.bankCode - Bank code/identifier
   * @param {Object} [disbursementData.metadata] - Optional metadata
   * @returns {Promise<Object>} API response from the disbursement request
   */
  async createBankB2CDisbursement(disbursementData) {
    if (!disbursementData || !disbursementData.amount || !disbursementData.customer || !disbursementData.paymentDetails) {
      throw new Error('Incomplete disbursement data');
    }

    if (!disbursementData.paymentDetails.accountNumber || !disbursementData.paymentDetails.bankCode) {
      throw new Error('Bank account number and bank code are required for bank disbursements');
    }

    const headers = {};
    const userId = getStoredUserId();

    if (userId) {
      // Ensure userId is a string (UUID from login response: data.user.id)
      headers['x-user-id'] = String(userId);
    } else {
      throw new Error('User ID not found. Please log in again.');
    }

    const body = {
      reference: disbursementData.reference,
      disburseType: disbursementData.disburseType || 'deposit',
      customer: disbursementData.customer,
      narration: disbursementData.narration,
      channel: 'BANK',
      amount: disbursementData.amount,
      currency: disbursementData.currency || 'GHS',
      paymentDetails: {
        accountNumber: disbursementData.paymentDetails.accountNumber,
        accountName: disbursementData.paymentDetails.accountName,
        bankCode: disbursementData.paymentDetails.bankCode,
        ...disbursementData.paymentDetails,
      },
    };

    // Include source field if present
    if (disbursementData.source) {
      body.source = disbursementData.source;
    }

    if (disbursementData.metadata) {
      body.metadata = disbursementData.metadata;
    }

    const response = await apiRequest('/v1/disbursements', {
      method: 'POST',
      body: JSON.stringify(body),
      headers,
    });

    return response;
  },

